INSERT INTO spots VALUES('7cc40fca-d678-46e7-b137-164b05b904e6','fukui-castle-loop','福井城址周回','ふくいじょうししゅうかい','福井県','福井市',36.06218100000000248,136.2178869999999904,'福井城址の南側から内堀と県庁周辺を囲み、福井駅側の市街地をつないで一周する約3.4kmのコースです。石垣と堀、御廊下橋、山里口御門などを眺められ、駅周辺のホテルから短時間で走れます。ほぼ平坦で朝ランにも使いやすい一方、県庁周辺の歩道と交差点では通行者や車に注意してください。','JR・ハピラインふくい 福井駅から徒歩約10分',1,0,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837527788);
INSERT INTO spots VALUES('151a591e-3383-4a7e-8319-822a2ee1b703','hamamatsu-castle-park','浜松城公園周回','はままつじょうこうえんしゅうかい','静岡県','浜松市中央区',34.70883500000000054,137.7223390000000051,'浜松城公園の南側から天守閣、作左の森、日本庭園、市役所周辺を囲む約3.2kmの周回です。浜松市がウォーキングコースと距離表示看板を整備している公園で、徳川家康ゆかりの城と緑を楽しめます。適度な起伏があり、短い朝ランや坂を含むジョグに向きます。園内では散策者を優先してください。','遠州鉄道 遠州病院駅から徒歩約15分。浜松駅からバスで市役所南下車',1,1,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837526622);
INSERT INTO spots VALUES('1dfc832f-7098-4799-a3f2-1ef082265178','inuyama-castle-kisogawa','犬山城・木曽川周回','いぬやまじょう・きそがわしゅうかい','愛知県','犬山市',35.38802199999999943,136.9383579999999939,'国宝犬山城の麓から木曽川河畔、城下町の本町通り周辺をつないで一周する約6kmのコースです。現存天守と木曽川の景色、歴史ある町並みを一度に楽しめます。犬山市の公式ウォーキングマップでも城下町散策と木曽川河畔のコースが案内されています。城下町の混雑時は歩行者を優先してください。','名鉄 犬山遊園駅から徒歩約15分。犬山駅から城下町経由で徒歩約20分',1,0,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837527017);
INSERT INTO spots VALUES('636a7027-a62b-4488-bf28-40bd897d221b','marugame-castle-loop','丸亀城周回','まるがめじょうしゅうかい','香川県','丸亀市',34.28222099999999984,133.7981509999999901,'丸亀城の南側から大手門、亀山公園外周、市役所周辺をつないで一周する約3.5kmのコースです。現存天守へ続く高石垣をさまざまな方向から眺められ、城下町の平坦な道を中心に走れます。丸亀市の公式ウォーキングマップでも丸亀城コースが案内されています。園内や大手門付近では観光客を優先してください。','JR丸亀駅から南へ徒歩約15分',1,1,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837526237);
INSERT INTO spots VALUES('80591349-69e5-4019-a55a-dc29e878cc42','nijo-castle-loop','二条城外周','にじょうじょうがいしゅう','京都府','京都市中京区',35.0101980000000026,135.7445769999999925,'元離宮二条城の南東側から、堀沿いの歩道と城北・城西の街路をつないで一周する約3.8kmの都市型コースです。東大手門、石垣、堀を眺めながら平坦に走れ、地下鉄駅からすぐ始められます。京都中心部で距離を把握しやすい朝ランコースですが、観光客や通勤通学の歩行者が多い時間帯は速度を落としてください。','京都市営地下鉄 二条城前駅からすぐ',1,0,1,0,0,0,1,1,'bright',NULL,1,1783837525000,1783837529088);
INSERT INTO spots VALUES('0d1fb0e1-ea8a-4b23-969f-397f21cd068c','shuri-castle-loop','首里城周回','しゅりじょうしゅうかい','沖縄県','那覇市',26.2134450000000001,127.7140919999999938,'首里城公園の南側から守礼門周辺、龍潭、首里の城下町をつないで一周する約4.7kmのコースです。琉球王国の城郭と石畳、赤瓦の町並みを楽しめ、約126mの獲得標高がある坂道中心のお城ランです。石畳は雨天時に滑りやすく、観光客の多い場所や狭い生活道路では無理に走らず歩行者を優先してください。','ゆいレール 首里駅から徒歩約15分',1,1,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837529961);
INSERT INTO spots VALUES('e155cc4d-3685-4ed7-9b8e-442d7f434ba2','takada-castle-park','高田城址公園周回','たかだじょうしこうえんしゅうかい','新潟県','上越市',37.10479699999999781,138.2488889999999913,'高田城址公園の南側から外堀沿い、三重櫓、陸上競技場周辺を囲んで一周する約4.3kmのコースです。広い堀と桜並木を眺めながら、ほぼ平坦な公園外周を走れます。周回で距離を追加しやすく、上越市街での朝ランにも便利です。観桜会の時期は非常に混雑するため、早朝を選び歩行者を優先してください。','えちごトキめき鉄道 高田駅から徒歩約25分。高田城址公園バス停からすぐ',1,1,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837528190);
INSERT INTO spots VALUES('ffb7ca05-1328-4e26-99a3-cb98bf630d27','ueda-castle-park','上田城跡公園周回','うえだじょうせきこうえんしゅうかい','長野県','上田市',36.40051299999999656,138.2410130000000094,'上田城跡公園の南側から尼ヶ淵、二の丸濠跡、北側の街路をつないで一周する約3.9kmのコースです。真田氏ゆかりの櫓や石垣、濠跡を眺めながら適度な起伏を走れます。上田市公式でも城内散策コースや城下町約6kmのウォーキングコースが紹介されています。桜の時期や園内では歩行者を優先してください。','しなの鉄道・北陸新幹線 上田駅から徒歩約15分',1,1,1,0,0,0,1,1,'partial',NULL,1,1783837525000,1783837527400);
